@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun DetailScreen(
    onBackClick: () -> Unit,
    onNavigateToDownload: () -> Unit = {},
    viewModel: DetailViewModel = hiltViewModel()
) {
    val message by viewModel.message.collectAsState()
    val investigationState by viewModel.investigationState.collectAsState()
    val showDownloadPrompt by viewModel.showDownloadPrompt.collectAsState()
    val modelState by viewModel.modelState.collectAsState()
    val context = LocalContext.current

    var badgeVisible by remember { mutableStateOf(false) }

    val isInvestigating = investigationState.progress > 0 && investigationState.verdict == null
    val isModelReady = modelState == ModelRepository.State.READY

    // Pulsing animation for Deep Check running
    val pulseAnimation by rememberInfiniteTransition(label = "pulse").animateFloat(
        initialValue = 1f,
        targetValue = 1.03f,
        animationSpec = infiniteRepeatable(
            animation = tween(1000, easing = FastOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "pulseScale"
    )

    LaunchedEffect(message?.classification) {
        badgeVisible = false
        kotlinx.coroutines.delay(100)
        badgeVisible = true
    }

    if (showDownloadPrompt) {
        AlertDialog(
            onDismissRequest = { viewModel.onDownloadPromptDismissed() },
            title = { Text(stringResource(R.string.download_prompt_title)) },
            text = {
                Text(stringResource(R.string.download_prompt_desc))
            },
            confirmButton = {
                TextButton(onClick = {
                    viewModel.onDownloadPromptDismissed()
                    onNavigateToDownload()
                }) {
                    Text(stringResource(R.string.download))
                }
            },
            dismissButton = {
                TextButton(onClick = { viewModel.onDownloadPromptDismissed() }) {
                    Text(stringResource(R.string.use_rule_based))
                }
            }
        )
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(stringResource(R.string.sms_detail)) },
                navigationIcon = {
                    IconButton(onClick = onBackClick) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = stringResource(R.string.cancel))
                    }
                },
                actions = {
                    // Share button in top bar
                    message?.let { sms ->
                        IconButton(onClick = {
                            shareMessage(context, sms.sender, sms.text, investigationState.verdict)
                        }) {
                            Icon(Icons.Default.Share, contentDescription = "Share")
                        }
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = MaterialTheme.colorScheme.surface,
                    titleContentColor = MaterialTheme.colorScheme.onSurface
                )
            )
        }
    ) { padding ->
        message?.let { sms ->
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(padding)
                    .verticalScroll(rememberScrollState())
                    .padding(16.dp),
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                // ── Message Card ──
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(16.dp),
                    elevation = CardDefaults.cardElevation(defaultElevation = 2.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.surfaceContainerHigh
                    )
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(16.dp),
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(10.dp)
                            ) {
                                // Sender avatar
                                val avatarColor = when (sms.classification?.label?.uppercase()) {
                                    "SCAM" -> ScamRed
                                    "SUSPICIOUS" -> SuspiciousOrange
                                    "SAFE" -> SafeGreen
                                    else -> LowGray
                                }
                                Box(
                                    modifier = Modifier
                                        .size(40.dp)
                                        .clip(CircleShape)
                                        .background(avatarColor.copy(alpha = 0.12f)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(
                                        text = sms.sender.firstOrNull()?.uppercase() ?: "?",
                                        color = avatarColor,
                                        fontWeight = FontWeight.Bold,
                                        fontSize = 16.sp
                                    )
                                }
                                Column {
                                    Text(
                                        text = sms.sender,
                                        fontWeight = FontWeight.Bold,
                                        style = MaterialTheme.typography.titleMedium
                                    )
                                    Text(
                                        text = SimpleDateFormat("MMM dd, yyyy • hh:mm a", Locale.getDefault())
                                            .format(Date(sms.timestamp)),
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.5f)
                                    )
                                }
                            }
                        }

                        HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant)

                        Text(
                            text = sms.text,
                            style = MaterialTheme.typography.bodyLarge,
                            lineHeight = 24.sp
                        )
                    }
                }

                // ── Classification Card ──
                sms.classification?.let { classification ->
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        shape = RoundedCornerShape(16.dp),
                        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
                    ) {
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(16.dp),
                            verticalArrangement = Arrangement.spacedBy(14.dp)
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Text(text = "\uD83D\uDCCA", fontSize = 18.sp)
                                Text(
                                    text = stringResource(R.string.classification),
                                    fontWeight = FontWeight.Bold,
                                    style = MaterialTheme.typography.titleMedium
                                )
                            }

                            AnimatedVisibility(
                                visible = badgeVisible,
                                enter = scaleIn(
                                    animationSpec = spring(
                                        dampingRatio = Spring.DampingRatioMediumBouncy,
                                        stiffness = Spring.StiffnessLow
                                    )
                                ) + fadeIn(),
                                exit = fadeOut()
                            ) {
                                ShieldBadge(
                                    label = classification.label,
                                    riskScore = classification.riskScore,
                                    animated = true
                                )
                            }

                            RiskScoreBar(riskScore = classification.riskScore)

                            Text(
                                text = classification.reasoning,
                                style = MaterialTheme.typography.bodyMedium,
                                color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.7f)
                            )
                        }
                    }
                }

                // ── Privacy Indicator ──
                PrivacyIndicator()

                // ── Deep Check Section ──
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(16.dp),
                    elevation = CardDefaults.cardElevation(defaultElevation = 2.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.surfaceContainer
                    )
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(16.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Text(text = "\uD83E\uDD16", fontSize = 18.sp)
                            Text(
                                text = "AI Deep Analysis",
                                fontWeight = FontWeight.Bold,
                                style = MaterialTheme.typography.titleMedium
                            )
                        }

                        // Dynamic button based on model state
                        when (modelState) {
                            ModelRepository.State.IDLE, ModelRepository.State.FAILED -> {
                                Button(
                                    onClick = onNavigateToDownload,
                                    modifier = Modifier.fillMaxWidth(),
                                    shape = RoundedCornerShape(12.dp),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.tertiary
                                    )
                                ) {
                                    Icon(Icons.Default.Lock, contentDescription = null, Modifier.size(18.dp))
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Text(
                                        text = "Download AI Model (~2.7 GB)",
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                                Text(
                                    text = "Get complete protection against sophisticated scams.",
                                    style = MaterialTheme.typography.bodySmall,
                                    textAlign = TextAlign.Center,
                                    color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.6f),
                                    modifier = Modifier.fillMaxWidth()
                                )
                            }

                            ModelRepository.State.DOWNLOADING -> {
                                Button(
                                    onClick = onNavigateToDownload,
                                    modifier = Modifier.fillMaxWidth(),
                                    shape = RoundedCornerShape(12.dp),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.primary
                                    )
                                ) {
                                    CircularProgressIndicator(
                                        modifier = Modifier.size(16.dp),
                                        strokeWidth = 2.dp,
                                        color = MaterialTheme.colorScheme.onPrimary
                                    )
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Text("Downloading...")
                                }
                            }

                            ModelRepository.State.VERIFYING, ModelRepository.State.LOADING -> {
                                Button(
                                    onClick = { /* Disabled */ },
                                    modifier = Modifier.fillMaxWidth(),
                                    shape = RoundedCornerShape(12.dp),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.surfaceVariant
                                    ),
                                    enabled = false
                                ) {
                                    CircularProgressIndicator(
                                        modifier = Modifier.size(16.dp),
                                        strokeWidth = 2.dp
                                    )
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Text("Initializing AI Engine...")
                                }
                            }

                            ModelRepository.State.READY -> {
                                Button(
                                    onClick = { viewModel.startDeepCheck() },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .then(
                                            if (isInvestigating) Modifier.scale(pulseAnimation)
                                            else Modifier
                                        ),
                                    shape = RoundedCornerShape(12.dp),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = if (isInvestigating) {
                                            MaterialTheme.colorScheme.secondaryContainer
                                        } else {
                                            MaterialTheme.colorScheme.primary
                                        }
                                    ),
                                    enabled = !isInvestigating
                                ) {
                                    if (isInvestigating) {
                                        CircularProgressIndicator(
                                            modifier = Modifier.size(16.dp),
                                            strokeWidth = 2.dp,
                                            color = MaterialTheme.colorScheme.onSecondaryContainer
                                        )
                                        Spacer(modifier = Modifier.width(8.dp))
                                        Text(
                                            text = "Analyzing...",
                                            color = MaterialTheme.colorScheme.onSecondaryContainer
                                        )
                                    } else {
                                        Icon(Icons.Default.Search, contentDescription = null, Modifier.size(18.dp))
                                        Spacer(modifier = Modifier.width(8.dp))
                                        Text(
                                            text = if (investigationState.verdict != null) {
                                                "Run Again"
                                            } else {
                                                "⚡ Run Deep Analysis"
                                            },
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }
                        }
                    }
                }

                // ── Analysis Progress / Timeline ──
                AnimatedVisibility(
                    visible = isInvestigating,
                    enter = expandVertically() + fadeIn(),
                    exit = shrinkVertically() + fadeOut()
                ) {
                    AnalysisProgressCard(
                        progress = investigationState.progress,
                        currentStep = investigationState.currentStep
                    )
                }

                // ── Deep Check Timeline (when results exist) ──
                if (investigationState.progress > 0 || investigationState.verdict != null || investigationState.error != null) {
                    DeepCheckTimeline(
                        state = investigationState,
                        onCancel = { viewModel.cancelDeepCheck() }
                    )
                }

                // ── Verdict (with share) ──
                investigationState.verdict?.let { verdict ->
                    VerdictCard(
                        verdict = verdict,
                        onShareClick = {
                            shareVerdict(context, sms.sender, verdict)
                        }
                    )
                }

                Spacer(modifier = Modifier.height(16.dp))
            }
        } ?: run {
            // Loading state
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(padding),
                contentAlignment = Alignment.Center
            ) {
                Column(
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    CircularProgressIndicator()
                    Text(
                        text = "Loading message...",
                        style = MaterialTheme.typography.bodyMedium,
                        color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.6f)
                    )
                }
            }
        }
    }
}

@Composable
private fun AnalysisProgressCard(
    progress: Int,
    currentStep: String?
) {
    val animatedProgress by animateFloatAsState(
        targetValue = progress / 100f,
        animationSpec = tween(500, easing = FastOutSlowInEasing),
        label = "analysisProgress"
    )

    // Scanning dot animation
    val dotAlpha by rememberInfiniteTransition(label = "dot").animateFloat(
        initialValue = 0.3f,
        targetValue = 1f,
        animationSpec = infiniteRepeatable(
            animation = tween(600),
            repeatMode = RepeatMode.Reverse
        ),
        label = "dotAlpha"
    )

    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.3f)
        )
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "🔍 Analyzing...",
                    style = MaterialTheme.typography.titleSmall,
                    fontWeight = FontWeight.SemiBold
                )
                Text(
                    text = "$progress%",
                    style = MaterialTheme.typography.titleSmall,
                    color = MaterialTheme.colorScheme.primary,
                    fontWeight = FontWeight.Bold
                )
            }

            LinearProgressIndicator(
                progress = { animatedProgress },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(6.dp)
                    .clip(RoundedCornerShape(3.dp)),
                color = MaterialTheme.colorScheme.primary,
                trackColor = MaterialTheme.colorScheme.surfaceVariant
            )

            currentStep?.let { step ->
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .size(6.dp)
                            .clip(CircleShape)
                            .background(
                                MaterialTheme.colorScheme.primary.copy(alpha = dotAlpha)
                            )
                    )
                    Text(
                        text = step,
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.7f)
                    )
                }
            }
        }
    }
}

private fun shareMessage(context: Context, sender: String, text: String, verdict: DeepCheckVerdict?) {
    val shareText = buildString {
        appendLine("SMS from: $sender")
        appendLine(text)
        if (verdict != null) {
            appendLine()
            appendLine("SMSentry Analysis: ${if (verdict.isScam) "⚠️ SCAM DETECTED" else "✅ SAFE"}")
            appendLine(verdict.summary)
        }
        appendLine()
        appendLine("— Analyzed by SMSentry")
    }
    val intent = Intent(Intent.ACTION_SEND).apply {
        type = "text/plain"
        putExtra(Intent.EXTRA_TEXT, shareText)
    }
    context.startActivity(Intent.createChooser(intent, "Share via"))
}

private fun shareVerdict(context: Context, sender: String, verdict: DeepCheckVerdict) {
    val shareText = buildString {
        appendLine("SMSentry Deep Check Result")
        appendLine("━━━━━━━━━━━━━━━━━━")
        appendLine("Sender: $sender")
        appendLine("Verdict: ${if (verdict.isScam) "🛑 SCAM DETECTED" else "🛡️ MESSAGE SAFE"}")
        verdict.threatType?.let { appendLine("Threat: ${it.replace("_", " ")}") }
        appendLine()
        appendLine(verdict.summary)
        if (verdict.recommendedActions.isNotEmpty()) {
            appendLine()
            appendLine("Actions:")
            verdict.recommendedActions.forEach { appendLine("• $it") }
        }
        appendLine()
        appendLine("— Analyzed by SMSentry")
    }
    val intent = Intent(Intent.ACTION_SEND).apply {
        type = "text/plain"
        putExtra(Intent.EXTRA_TEXT, shareText)
    }
    context.startActivity(Intent.createChooser(intent, "Share verdict"))
}

package com.smssentry.ui.navigation

import android.util.Log
import androidx.compose.animation.*
import androidx.compose.animation.core.FastOutSlowInEasing
import androidx.compose.animation.core.tween
import androidx.compose.runtime.Composable
import androidx.navigation.NavHostController
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.navArgument
import com.smssentry.deepcheck.ui.ModelDownloadScreen
import com.smssentry.ui.detail.DetailScreen
import com.smssentry.ui.inbox.InboxScreen
import com.smssentry.ui.theme.ThemePreferenceRepository

sealed class Screen(val route: String) {
    data object Inbox : Screen("inbox")
    data object Detail : Screen("detail/{smsId}") {
        fun createRoute(smsId: String) = "detail/$smsId"
    }
    data object ModelDownload : Screen("model_download")
}

private const val TAG = "NavGraph"
private const val NAV_ANIM_DURATION = 350

@Composable
fun SMSSentryNavGraph(
    navController: NavHostController,
    themeRepository: ThemePreferenceRepository
) {
    NavHost(
        navController = navController,
        startDestination = Screen.Inbox.route,
        enterTransition = {
            slideInHorizontally(
                initialOffsetX = { it },
                animationSpec = tween(NAV_ANIM_DURATION, easing = FastOutSlowInEasing)
            ) + fadeIn(animationSpec = tween(NAV_ANIM_DURATION))
        },
        exitTransition = {
            slideOutHorizontally(
                targetOffsetX = { -it / 4 },
                animationSpec = tween(NAV_ANIM_DURATION, easing = FastOutSlowInEasing)
            ) + fadeOut(animationSpec = tween(NAV_ANIM_DURATION / 2))
        },
        popEnterTransition = {
            slideInHorizontally(
                initialOffsetX = { -it / 4 },
                animationSpec = tween(NAV_ANIM_DURATION, easing = FastOutSlowInEasing)
            ) + fadeIn(animationSpec = tween(NAV_ANIM_DURATION))
        },
        popExitTransition = {
            slideOutHorizontally(
                targetOffsetX = { it },
                animationSpec = tween(NAV_ANIM_DURATION, easing = FastOutSlowInEasing)
            ) + fadeOut(animationSpec = tween(NAV_ANIM_DURATION / 2))
        }
    ) {
        composable(Screen.Inbox.route) {
            InboxScreen(
                onMessageClick = { smsId ->
                    navController.navigate(Screen.Detail.createRoute(smsId))
                },
                themeRepository = themeRepository
            )
        }

        composable(
            route = Screen.Detail.route,
            arguments = listOf(
                navArgument("smsId") { type = NavType.StringType }
            )
        ) {
            DetailScreen(
                onBackClick = { navController.popBackStack() },
                onNavigateToDownload = {
                    navController.navigate(Screen.ModelDownload.route)
                }
            )
        }

        composable(
            route = Screen.ModelDownload.route,
            enterTransition = {
                slideInVertically(
                    initialOffsetY = { it },
                    animationSpec = tween(NAV_ANIM_DURATION, easing = FastOutSlowInEasing)
                ) + fadeIn(animationSpec = tween(NAV_ANIM_DURATION))
            },
            popExitTransition = {
                slideOutVertically(
                    targetOffsetY = { it },
                    animationSpec = tween(NAV_ANIM_DURATION, easing = FastOutSlowInEasing)
                ) + fadeOut(animationSpec = tween(NAV_ANIM_DURATION / 2))
            }
        ) {
            ModelDownloadScreen(
                onBackClick = {
                    val backQueue = navController.currentBackStack.value.map { it.destination.route }
                    Log.d(TAG, "backQueue before pop: $backQueue")
                    if (!navController.popBackStack()) {
                        Log.w(TAG, "popBackStack returned false, navigating to Inbox")
                        navController.navigate(Screen.Inbox.route) {
                            popUpTo(Screen.Inbox.route) { inclusive = true }
                        }
                    }
                }
            )
        }
    }
}

